const { spawn } = require('child_process');
const SUPA_KEY = $env.SUPABASE_SERVICE_KEY
  || $env.SUPABASE_SERVICE_ROLE_KEY
  || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImF6d3Bsbmpsa2Zjc3picmZhZWh2Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MTgyODMwMiwiZXhwIjoyMDk3NDA0MzAyfQ.pqytRJKDJoDvHuYr5R40b_ifbL8saDfB8MVsM5VTnOc';
const items = $input.all().map(i => i.json);

if (!items.length) return [{ json: { items: [], totalItems: 0, supaStatus: null } }];

const SCRAPER = `(async () => {
  const puppeteer = require('/usr/local/lib/node_modules/puppeteer');
  const https = require('https');
  const BASE = 'https://comprar.gob.ar';
  const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0 Safari/537.36';
  let inputData = '';
  process.stdin.setEncoding('utf8');
  process.stdin.on('data', function(d) { inputData += d; });
  process.stdin.on('end', async function() {
    const parsed = JSON.parse(inputData);
    const items = parsed.items;
    const supaKey = parsed.supaKey;
    let browser;
    try {
      browser = await puppeteer.launch({
        executablePath: '/usr/bin/chromium-browser',
        args: ['--no-sandbox','--disable-setuid-sandbox','--disable-dev-shm-usage','--disable-gpu','--single-process','--no-zygote'],
        headless: true, timeout: 60000,
      });
      const results = [];
      for (let i = 0; i < items.length; i++) {
        const lic = items[i];
        const page = await browser.newPage();
        try {
          await page.setUserAgent(UA);
          page.setDefaultNavigationTimeout(25000);
          await page.goto(BASE + '/BuscarAvanzado.aspx', { waitUntil: 'domcontentloaded', timeout: 30000 });
          await page.type('#ctl00_CPH1_txtNumeroProceso', String(lic.numero));
          await page.click('#ctl00_CPH1_btnListarPliegoNumero');
          let linkEl = null;
          try {
            await page.waitForSelector('a[id*="lnkNumeroProceso"]', { timeout: 12000 });
            linkEl = await page.$('a[id*="lnkNumeroProceso"]');
          } catch(e) {
            console.error('[' + lic.numero + '] FALLO: no link');
            results.push(Object.assign({}, lic, { _err: 1 }));
            await page.close().catch(function() {});
            continue;
          }
          await Promise.all([
            page.waitForNavigation({ waitUntil: 'domcontentloaded', timeout: 20000 }),
            linkEl.click(),
          ]);
          const detailUrl = page.url();
          const html = await page.content();
          function textById(id) {
            const m = html.match(new RegExp('id="' + id + '"[^>]*>([^<]*)<', 'i'));
            return m ? m[1].replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').trim() || null : null;
          }
          const P = 'ctl00_CPH1_UCVistaPreviaPliego_';
          const renglones = [];
          const tblM = html.match(new RegExp('id="' + P + 'UC_DetalleProductos_gvLineaPliego"[^]*?<[/]table>', 'i'));
          if (tblM) {
            let rm; const rowRe = /<tr[^>]*>([^]*?)<[/]tr>/gi;
            while ((rm = rowRe.exec(tblM[0])) !== null) {
              let tm; const tdRe = /<td[^>]*>([^]*?)<[/]td>/gi; const tds = [];
              while ((tm = tdRe.exec(rm[1])) !== null) tds.push(tm[1].replace(/<[^>]+>/g,'').replace(/&nbsp;/g,' ').trim());
              if (tds.length >= 4 && /^[0-9]+$/.test(tds[0])) renglones.push({ nro:tds[0], codigo:tds[2]||null, descripcion:tds[3]||null, cantidad:tds[4]||null });
            }
          }
          console.error('[' + lic.numero + '] OK url=' + detailUrl.slice(0,60));
          results.push(Object.assign({}, lic, {
            url_detalle: detailUrl,
            modalidad: textById(P + 'UC_InformacionBasica_lblModalidad'),
            tipo_procedimiento: textById(P + 'UC_InformacionBasica_lblProcedimientoSeleccion'),
            cronograma_detalle: { publicacion: textById(P + 'UC_Cronograma_lblFechaPublicacion'), apertura: textById(P + 'UC_Cronograma_lblFechaApertura') || textById(P + 'UC_Cronograma_lblFechaActoApertura') },
            renglones: renglones.length ? renglones : null,
          }));
        } catch(e) {
          console.error('[' + lic.numero + '] EXC ' + String(e).slice(0,80));
          results.push(Object.assign({}, lic, { _err: 1 }));
        } finally {
          await page.close().catch(function() {});
        }
      }
      await browser.close().catch(function() {});
      const clean = results.map(function(it) {
        const c = {}; Object.keys(it).forEach(function(k) { if (k.charAt(0) !== '_') c[k] = it[k]; }); return c;
      });
      const supaResult = await new Promise(function(resolve) {
        const payload = JSON.stringify(clean);
        let statusCode = 0;
        let body = '';
        const req = https.request({
          hostname: 'azwplnjlkfcszbrfaehv.supabase.co',
          path: '/rest/v1/licitaciones?on_conflict=portal,numero',
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(payload),
            'apikey': supaKey,
            'Authorization': 'Bearer ' + supaKey,
            'Prefer': 'resolution=merge-duplicates,return=minimal',
          },
        }, function(res) {
          statusCode = res.statusCode;
          res.on('data', function(d) { body += d.toString(); });
          res.on('end', function() { resolve({ status: statusCode, body: body }); });
        });
        req.on('error', function(e) { resolve({ status: 0, body: 'net_err:' + e.message }); });
        req.write(payload); req.end();
      });
      const supaOk = supaResult.status >= 200 && supaResult.status < 300;
      console.error('SUPA status=' + supaResult.status + (supaOk ? ' OK' : ' ERR=' + supaResult.body.slice(0,150)));
      console.log(JSON.stringify({ ok: true, supaStatus: supaResult.status, supaBody: supaOk ? '' : supaResult.body.slice(0,300), items: clean }));
    } catch(e) {
      if (browser) await browser.close().catch(function() {});
      console.log(JSON.stringify({ ok: false, error: String(e) }));
    }
  });
})();`;

const rawResult = await new Promise(function(resolve, reject) {
  let out = '';
  const proc = spawn('node', ['-e', SCRAPER], {
    env: { PUPPETEER_EXECUTABLE_PATH: '/usr/bin/chromium-browser', PUPPETEER_SKIP_DOWNLOAD: 'true', NODE_PATH: '/usr/local/lib/node_modules', HOME: '/home/node', PATH: '/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin' }
  });
  proc.stdin.write(JSON.stringify({ items: items, supaKey: SUPA_KEY }));
  proc.stdin.end();
  proc.stdout.on('data', function(buf) { out += buf.toString(); });
  proc.stderr.on('data', function(buf) { console.log('SPAWN: ' + buf.toString().trim()); });
  const timer = setTimeout(function() { try { proc.kill(); } catch(_) {} reject(new Error('Timeout 300s')); }, 300000);
  proc.on('close', function() { clearTimeout(timer); resolve(out); });
  proc.on('error', function(err) { clearTimeout(timer); reject(err); });
});

let parsed;
try { parsed = JSON.parse(rawResult.trim()); }
catch(e) { parsed = { ok: false, error: 'parse:' + String(e) + ' raw:' + rawResult.slice(0,300), items: [] }; }
if (!parsed.ok) console.log('Error spawn: ' + (parsed.error || 'unknown'));
return [{ json: { items: parsed.items || [], totalItems: (parsed.items||[]).length, supaStatus: parsed.supaStatus || null, supaBody: parsed.supaBody || null } }];

